import{_ as l,o as e,c as t,a2 as o}from"./chunks/framework.DIMps2S2.js";const p=JSON.parse('{"title":"如何开通余额通","description":"","frontmatter":{"layout":"doc","sidebar":true},"headers":[],"relativePath":"funds-and-wealth/how-to-enable-cash-plus.md","filePath":"zh-CN/funds-and-wealth/how-to-enable-cash-plus.md"}'),i={name:"funds-and-wealth/how-to-enable-cash-plus.md"};function r(s,a,n,h,d,u){return e(),t("div",null,[...a[0]||(a[0]=[o('<h1 id="如何开通余额通" tabindex="-1">如何开通余额通 <a class="header-anchor" href="#如何开通余额通" aria-label="Permalink to &quot;如何开通余额通&quot;">​</a></h1><p>本指南说明如何在长桥 App 开通余额通，并完成首次自动转入授权。</p><blockquote><p>余额通将账户闲置资金自动投入货币市场基金，开通后无需手动操作。了解产品特点见<a href="/wiki/funds-and-wealth/cash-plus/cash-plus">余额通</a>。</p></blockquote><hr><h2 id="开通步骤" tabindex="-1">开通步骤 <a class="header-anchor" href="#开通步骤" aria-label="Permalink to &quot;开通步骤&quot;">​</a></h2><ol><li>打开长桥 App，点击底部导航栏「<strong>市场</strong>」</li><li>选择「<strong>财富</strong>」→「<strong>闲钱理财</strong>」</li><li>点击「<strong>余额通</strong>」，进入开通页面</li><li>阅读产品说明，选择目标货币基金（港元或美元）</li><li>点击「<strong>开通并授权</strong>」，完成自动申购授权</li><li>授权确认后，余额通即时生效</li></ol><blockquote><p>开通后，每个交易日系统会在固定时间自动将闲置资金转入所选基金。具体时间：香港账户为 8:30，新加坡账户为 10:00。</p></blockquote><hr><h2 id="修改默认基金" tabindex="-1">修改默认基金 <a class="header-anchor" href="#修改默认基金" aria-label="Permalink to &quot;修改默认基金&quot;">​</a></h2><p>开通后如需更换自动申购的基金：</p><ol><li>进入「市场」→「财富」→「闲钱理财」→「余额通」</li><li>点击右上角设置图标</li><li>选择新的默认基金并确认</li></ol><p>修改在下一个自动申购时间点生效。</p><hr><h2 id="关闭余额通" tabindex="-1">关闭余额通 <a class="header-anchor" href="#关闭余额通" aria-label="Permalink to &quot;关闭余额通&quot;">​</a></h2><ol><li>进入「市场」→「财富」→「闲钱理财」→「余额通」</li><li>点击右上角设置图标，选择「关闭余额通」</li><li>确认关闭</li></ol><p>关闭后，系统在最近一个交易日赎回当前持仓，最晚 T+1 资金到账。</p><p><strong>注意</strong>：若账户持有融资仓位，关闭余额通会降低购买力，可能触发追缴保证金通知，请在关闭前确认账户风控状态。</p><hr><h2 id="相关文档" tabindex="-1">相关文档 <a class="header-anchor" href="#相关文档" aria-label="Permalink to &quot;相关文档&quot;">​</a></h2><ul><li><a href="/wiki/funds-and-wealth/cash-plus/cash-plus">余额通</a> — 运作机制、各市场规则与关闭说明</li><li><a href="/wiki/funds-and-wealth/idle-cash">闲钱理财</a> — 余额通与进阶理财产品对比</li></ul><h2 id="引用此页面的文档" tabindex="-1">引用此页面的文档 <a class="header-anchor" href="#引用此页面的文档" aria-label="Permalink to &quot;引用此页面的文档&quot;">​</a></h2><ul><li><a href="/wiki/funds-and-wealth/idle-cash">闲钱理财</a></li></ul>',22)])])}const f=l(i,[["render",r]]);export{p as __pageData,f as default};
